style.css:
body.theme-solarized-atelier {
  background-image: linear-gradient(180deg, rgba(7, 54, 66, 0.94), rgba(0, 43, 54, 0.98));
}

body.theme-solarized-atelier .panel,
body.theme-solarized-atelier .mode-panel,
body.theme-solarized-atelier .modal {
  border-color: rgba(38, 139, 210, 0.26);
  background: linear-gradient(180deg, rgba(11, 68, 82, 0.96), rgba(7, 54, 66, 0.94));
}

body.theme-solarized-atelier .page-title,
body.theme-solarized-atelier h1,
body.theme-solarized-atelier h2,
body.theme-solarized-atelier h3 {
  color: #fdf6e3;
  letter-spacing: 0.01em;
}

body.theme-solarized-atelier .btn,
body.theme-solarized-atelier .chip {
  border-radius: 999px;
}

body.theme-solarized-atelier .btn-accent {
  background: linear-gradient(135deg, #cb4b16, #dc322f);
  color: #fdf6e3;
}

body.theme-solarized-atelier .settings-pill.is-active,
body.theme-solarized-atelier .addons-tab.is-active {
  box-shadow: inset 0 0 0 1px rgba(253, 246, 227, 0.16);
}
